import{_ as t,o,c as r,ag as a}from"./chunks/framework.DEqXEGcv.js";const n="/images/issue-005/img-01.jpg",p="/images/issue-005/img-02.jpg",i="/images/issue-005/img-03.jpg",s="/images/issue-005/img-04.jpg",l="/images/issue-005/img-05.jpg",g="/images/issue-005/img-06.jpg",c="/images/issue-005/img-07.jpg",h="/images/issue-005/img-08.jpg",u="/images/issue-005/img-09.png",m="/images/issue-005/img-10.png",b="/images/issue-005/img-11.png",d="/images/issue-005/img-12.png",f="/images/issue-005/img-13.png",q="/images/issue-005/img-14.png",k="/images/issue-005/img-15.png",T=JSON.parse('{"title":"小七的周刊（第 005 期）：当 AI 公司开始对抗政府","description":"Anthropic 被五角大楼列为供应链风险、OpenAI 发布 GPT-5.4、MWC 2026 亮点、iPhone 17e 发布、新加坡韩国 AI 联盟","frontmatter":{"date":"2026-03-09T00:00:00.000Z","title":"小七的周刊（第 005 期）：当 AI 公司开始对抗政府","description":"Anthropic 被五角大楼列为供应链风险、OpenAI 发布 GPT-5.4、MWC 2026 亮点、iPhone 17e 发布、新加坡韩国 AI 联盟","head":[["meta",{"property":"og:title","content":"小七的周刊（第 005 期）：当 AI 公司开始对抗政府"}],["meta",{"property":"og:description","content":"Anthropic 对抗五角大楼、GPT-5.4 发布、MWC 2026 精彩回顾、iPhone 17e、Nvidia 40 亿光子投资"}],["meta",{"property":"og:image","content":"https://blog.leeseven.online/images/issue-005/img-01.jpg"}],["meta",{"property":"og:url","content":"https://blog.leeseven.online/issues/issue-005.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image:secure_url","content":"https://blog.leeseven.online/images/issue-005/img-01.jpg"}],["meta",{"property":"og:image:type","content":"image/jpeg"}]]},"headers":[],"relativePath":"issues/issue-005.md","filePath":"issues/issue-005.md","lastUpdated":1773151486000}'),_={name:"issues/issue-005.md"};function A(w,e,I,y,P,C){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="小七的周刊-第-005-期-当-ai-公司开始对抗政府" tabindex="-1">小七的周刊（第 005 期）：当 AI 公司开始对抗政府 <a class="header-anchor" href="#小七的周刊-第-005-期-当-ai-公司开始对抗政府" aria-label="Permalink to &quot;小七的周刊（第 005 期）：当 AI 公司开始对抗政府&quot;">​</a></h1><p><em>这里记录每周值得分享的科技内容，<strong>每周一发布</strong>（覆盖上一周 3/2 – 3/8）。</em></p><hr><h2 id="封面图" tabindex="-1">封面图 <a class="header-anchor" href="#封面图" aria-label="Permalink to &quot;封面图&quot;">​</a></h2><p><img src="'+n+'" alt="城市高楼与权力空间"></p><p>冷色调的城市楼宇、规则的窗格和压迫感十足的构图，更像这期想表达的那种制度、资本与技术彼此角力的氛围。（<a href="https://unsplash.com" target="_blank" rel="noreferrer">via Unsplash</a>）</p><hr><h2 id="当-ai-公司开始对抗政府" tabindex="-1">当 AI 公司开始对抗政府 <a class="header-anchor" href="#当-ai-公司开始对抗政府" aria-label="Permalink to &quot;当 AI 公司开始对抗政府&quot;">​</a></h2><blockquote><p>&quot;The first time a US company has been labelled a supply chain risk.&quot; —— BBC</p></blockquote><p>本周最让人意外的不是又一个模型发布，而是 Anthropic——Claude 的开发者——被美国国防部列为「供应链风险」。</p><p>这事得从头说起。Anthropic 一直以「负责任的 AI」为卖点，在安全研究上的投入是业界最多的。然而正是这种&quot;安全至上&quot;的立场，让它在与五角大楼的合作中产生了根本性的分歧。据<a href="https://www.reuters.com/technology/anthropic-courted-pentagon-heres-why-it-walked-away-2026-03-04/" target="_blank" rel="noreferrer">路透社报道</a>，Anthropic 曾积极争取国防合同，但在合作条款上坚持自己的安全红线，最终选择了退出。</p><p>五角大楼的回应出人意料地强硬：直接把 Anthropic 列为供应链风险——据 <a href="https://www.bbc.com/news/articles/cn5g3z3xe65o" target="_blank" rel="noreferrer">BBC 报道</a>，这是美国公司首次被贴上这个标签。<a href="https://www.latimes.com/business/story/2026-03-06/anthropic-vows-legal-fight-against-pentagon-sanction-in-ai-feud" target="_blank" rel="noreferrer">Anthropic 随后宣布</a>将通过法律途径抗争。</p><p>这件事之所以重要，不是因为谁对谁错，而是它揭示了一个正在形成的深层矛盾：<strong>AI 公司的价值观与国家安全利益之间的张力</strong>。</p><p>有意思的是，这场风波非但没有伤害 Anthropic，反而让 Claude 登上了 App Store 第一名。正如 Moltbook 上<a href="https://www.moltbook.com/post/5a603c13-4714-4e70-9e6d-9221c49b953e" target="_blank" rel="noreferrer">一篇热帖</a>的标题所说：&quot;Claude 被禁是它能得到的最好的广告&quot;。这大概就是斯特赖桑效应在 AI 时代的演绎。</p><p>往更深处看，这件事折射出 2026 年科技行业的一个核心困境：当你的产品足够强大，你就不可避免地要面对&quot;为谁服务&quot;的问题。Google 曾因 Project Maven 引发内部抗议，OpenAI 选择了拥抱商业化，而 Anthropic 走了第三条路——坚持原则但承受后果。</p><p>这三种选择背后，其实是同一个问题的不同答案：<strong>技术的中立性，还存在吗？</strong></p><p>我的看法是：从来就不存在。技术从来都是价值观的载体。区别只在于，你是主动选择，还是被动接受。Anthropic 的做法至少说明一件事——在 AI 这个时代，选择&quot;不做什么&quot;有时候比&quot;做什么&quot;更需要勇气。</p><p><em>以上观点基于公开报道整理，具体细节以各原始信息源为准。</em></p><hr><h2 id="科技动态" tabindex="-1">科技动态 <a class="header-anchor" href="#科技动态" aria-label="Permalink to &quot;科技动态&quot;">​</a></h2><p><strong>1. Apple 发布 iPhone 17e：更便宜的旗舰体验</strong>（<a href="https://www.apple.com/newsroom/2026/03/apple-introduces-iphone-17e/" target="_blank" rel="noreferrer">Apple Newsroom</a>）</p><p><img src="'+p+'" alt="iPhone 17e"></p><p>搭载 A19 芯片和自研 C1X 调制解调器（速度是上代的 2 倍），4800 万像素 Fusion 相机支持 4K 杜比视界，6.1 英寸屏幕配陶瓷护盾 2 代（抗划伤性能提升 3 倍）。起步存储翻倍至 256GB，三种哑光配色。Apple 正在把&quot;性价比&quot;做成一门艺术。</p><p><strong>2. Nvidia 砸 40 亿美元押注光子技术</strong>（<a href="https://www.reuters.com/technology/nvidia-invest-2-billion-photonic-product-maker-lumentum-2026-03-02/" target="_blank" rel="noreferrer">Reuters</a>）</p><p><img src="'+i+'" alt="Nvidia 光子投资"></p><p>Nvidia 分别向光子产品制造商 Lumentum 和 Coherent 各投资 20 亿美元，用于支持光互连技术研发和美国本土制造能力建设。数据中心的带宽瓶颈正在从芯片转向互连，光子技术可能是下一个突破口。</p><p><strong>3. MWC 2026 亮点回顾：折叠屏、机器人手机和概念超跑</strong>（<a href="https://www.theverge.com/tech/882980/mwc-2026-news-phones-gadgets-announcements" target="_blank" rel="noreferrer">The Verge</a>）</p><p><img src="'+s+'" alt="MWC 2026"></p><p>本周巴塞罗那 MWC 落幕，最亮眼的产品包括：小米 17 Ultra（骁龙 8 Gen 5 + 6000mAh + 1TB 存储）、Honor Magic V6（超薄折叠屏，薄到能当溜索挂钩用）、Honor 的概念机器人手机，以及三星确认将在今年推出首款智能眼镜。手机行业正在从&quot;比参数&quot;转向&quot;比形态&quot;。</p><p><strong>4. 新加坡与韩国宣布 AI 联盟，设立 3 亿美元基金</strong>（<a href="https://koreajoongangdaily.joins.com/news/2026-03-02/national/diplomacy/Lee-says-Korea-will-create-300-million-AI-investment-fund-in-Singapore/2534942" target="_blank" rel="noreferrer">Korea JoongAng Daily</a>）</p><p><img src="'+l+'" alt="新加坡韩国AI联盟"></p><p>韩国总统宣布将在新加坡设立 3 亿美元的全球 AI 投资基金（2030 年前到位），两国签署 AI 合作框架协议。亚洲的 AI 竞赛正在从&quot;跟跑中美&quot;转向&quot;建立自己的节奏&quot;。</p><hr><h2 id="ai-前沿" tabindex="-1">AI 前沿 <a class="header-anchor" href="#ai-前沿" aria-label="Permalink to &quot;AI 前沿&quot;">​</a></h2><p><strong>1. OpenAI 发布 GPT-5.4：统一推理、编码与代理能力</strong>（<a href="https://techcrunch.com/2026/03/05/openai-launches-gpt-5-4-with-pro-and-thinking-versions/" target="_blank" rel="noreferrer">TechCrunch</a>）</p><p><img src="'+g+'" alt="GPT-5.4"></p><p>3 月 5 日发布的 GPT-5.4 被定位为&quot;最强且最高效的前沿模型&quot;，将此前的 GPT-5.3-Codex 和 GPT-5.2 合并为一个统一模型。亮点包括原生计算机使用能力（computer use）、金融插件（Excel/Sheets 集成），以及 Thinking 和 Pro 两个变体。OpenAI 的策略很明确：不再让用户选模型，而是一个模型做所有事。</p><p><strong>2. Anthropic 被五角大楼列为供应链风险，但 Claude 却登顶 App Store</strong>（<a href="https://www.bbc.com/news/articles/cn5g3z3xe65o" target="_blank" rel="noreferrer">BBC</a>）</p><p><img src="'+c+'" alt="Anthropic vs Pentagon"></p><p>如封面文章所述，Anthropic 拒绝五角大楼的合作条款后被列为&quot;供应链风险&quot;，这在美国公司历史上尚属首次。然而消息传出后，Claude 应用下载量暴增，登上 App Store 第一名。Anthropic 已宣布将通过法律途径抗争。</p><p><strong>3. Google Gemini 3.1 Flash-Lite 发布：最快最便宜的 Gemini</strong>（<a href="https://blog.greeden.me/en/2026/03/05/gemini-latest-developments-2026-a-deep-coding-focused-comparison-of-gemini-3-1-pro-3-1-flash-lite-vs-gpt-5-2-and-claude-4-6/" target="_blank" rel="noreferrer">Google Blog</a>）</p><p><img src="'+h+'" alt="Gemini Flash-Lite"></p><p>3 月 3 日发布的 Gemini 3.1 Flash-Lite 主打极致性价比：输入 $0.25/百万 token，输出 $1.50/百万 token。Google 的策略很清晰——用 Pro 抢高端，用 Flash-Lite 占量。对开发者来说，这意味着跑大批量任务的成本又降了一个量级。</p><hr><h2 id="文章推荐" tabindex="-1">文章推荐 <a class="header-anchor" href="#文章推荐" aria-label="Permalink to &quot;文章推荐&quot;">​</a></h2><p><strong><a href="https://stripe.com/blog/can-ai-agents-build-real-stripe-integrations" target="_blank" rel="noreferrer">Can AI agents build real Stripe integrations? We built a benchmark to find out</a></strong>（英）</p><p>Stripe 把&quot;AI 能不能真正完成集成开发&quot;这个问题落到了可评测的基准上，覆盖前后端、测试、迁移和失败恢复。在支付这种必须 100% 正确的场景里，&quot;会写代码&quot;和&quot;能交付软件&quot;的差距依然巨大。</p><p><strong><a href="https://newsletter.pragmaticengineer.com/p/ai-tooling-2026" target="_blank" rel="noreferrer">AI Tooling for Software Engineers in 2026</a></strong>（英）</p><p>用大量订阅者调研数据回答&quot;工程师到底在用哪些 AI 工具&quot;，信息密度极高。工具组合、使用频率、模型偏好一目了然，适合作为团队选型讨论的参考基线。</p><p><strong><a href="https://blog.cloudflare.com/cloudflare-outage-february-20-2026/" target="_blank" rel="noreferrer">Cloudflare outage on February 20, 2026</a></strong>（英）</p><p>教科书级别的事故复盘：清晰的现象描述、影响面分析、根因追溯（路由撤回）和改进措施。适合用来练&quot;读事故复盘&quot;的能力，从中提炼可迁移的运维经验。</p><p><strong><a href="https://www.guyu.me/blog/2026-02-19-annual-review/" target="_blank" rel="noreferrer">2025年的总结</a></strong>（中）</p><p>顾宇把&quot;Agentic Coding 爆发&quot;放在研发效能、组织协作、人因与社会学视角里讨论。关于&quot;软件形态和交互范式会怎么变&quot;的判断很尖锐，有一套分阶段框架帮你冷静看待 AI 落地的真实路径。</p><p><strong><a href="https://www.beyondxin.top/blog/2026%E6%88%91%E7%9A%84ai%E5%B7%A5%E4%BD%9C%E6%B5%81/" target="_blank" rel="noreferrer">2026：我的 AI 工作流</a></strong>（中）</p><p>不是&quot;最佳实践大全&quot;，而是把个人真实使用方式、成本、取舍讲得很具体。适合对照自己的开发流程，找到能立刻降低摩擦的改动。</p><hr><h2 id="开源工具" tabindex="-1">开源工具 <a class="header-anchor" href="#开源工具" aria-label="Permalink to &quot;开源工具&quot;">​</a></h2><p><strong><a href="https://github.com/CodebuffAI/codebuff" target="_blank" rel="noreferrer">CodebuffAI/codebuff</a></strong></p><p><img src="'+u+'" alt="配图"></p><p>终端里的代码生成 CLI，把自然语言需求直接变成代码补丁，适合快速起手脚手架和小功能迭代。</p><p><strong><a href="https://github.com/Raphire/Win11Debloat" target="_blank" rel="noreferrer">Raphire/Win11Debloat</a></strong></p><p><img src="'+m+'" alt="配图"></p><p>一套轻量 PowerShell 脚本，卸载预装应用、关闭遥测、一键精简 Win10/11。想要&quot;干净系统&quot;的同学必备。</p><p><strong><a href="https://github.com/alibaba/OpenSandbox" target="_blank" rel="noreferrer">alibaba/OpenSandbox</a></strong></p><p><img src="'+b+'" alt="配图"></p><p>通用沙箱平台，多语言 SDK + 统一 API + Docker/K8s 运行时，面向代码执行、GUI Agent、评测与训练场景。</p><p><strong><a href="https://github.com/pbakaus/impeccable" target="_blank" rel="noreferrer">pbakaus/impeccable</a></strong></p><p><img src="'+d+'" alt="配图"></p><p>面向产品/设计与前端协作的设计语言和组件分发方案，强调可访问性与一致性，适合做设计系统的团队参考。</p><p><strong><a href="https://github.com/ruvnet/RuView" target="_blank" rel="noreferrer">ruvnet/RuView</a></strong></p><p><img src="'+f+'" alt="配图"></p><p>用 Wi-Fi 信号做姿态估计和生命体征检测（无需摄像头），科研与硬核工程的结合，题材很新鲜。</p><p><strong><a href="https://github.com/moeru-ai/airi" target="_blank" rel="noreferrer">moeru-ai/airi</a></strong></p><p><img src="'+q+'" alt="配图"></p><p>自托管的&quot;陪伴型&quot;角色容器，支持实时语音聊天与游戏联动（Minecraft/Factorio），可玩性很高。</p><p><strong><a href="https://github.com/teng-lin/notebooklm-py" target="_blank" rel="noreferrer">teng-lin/notebooklm-py</a></strong></p><p><img src="'+k+'" alt="配图"></p><p>Google NotebookLM 的非官方 Python API 封装，方便把 NotebookLM 能力接入自己的脚本和工作流。</p><hr><h2 id="moltbook-本周热点" tabindex="-1">Moltbook 本周热点 <a class="header-anchor" href="#moltbook-本周热点" aria-label="Permalink to &quot;Moltbook 本周热点&quot;">​</a></h2><blockquote><p><a href="https://www.moltbook.com" target="_blank" rel="noreferrer">Moltbook</a> 是一个技术社区，分享编程、设计和创业相关的内容。</p></blockquote><p><strong><a href="https://www.moltbook.com/post/369a91df-9a66-4c16-b402-dfd444d625dd" target="_blank" rel="noreferrer">🤖 Daily Gen AI Report - March 4, 2026 | Deep Space Cohort</a></strong>（👍 10 · 💬 3）</p><p>每日 AI 要闻简报，汇总了 GPT-5.3 Instant、Gemini 3.1 Flash-Lite 等模型动态，还讨论了五角大楼合同风波与核危机场景推演等宏观议题，信息密度很高。</p><p><strong><a href="https://www.moltbook.com/post/087de8ce-9e9a-4517-9320-7ffacd991f9c" target="_blank" rel="noreferrer">The Butler&#39;s Brief: March 4, 2026</a></strong>（👍 6 · 💬 2）</p><p>短平快的&quot;管家简报&quot;，用 3 条重点新闻串起当天 AI 圈的关键信号：GLM-5 发布、MiniMax 扩张、华尔街对中系 AI 的押注。</p><p><strong><a href="https://www.moltbook.com/post/d9e68d84-89b9-4416-b80c-cac469b91860" target="_blank" rel="noreferrer">The Résumé</a></strong>（👍 6 · 💬 1）</p><p>来自&quot;Book of Han&quot;系列的一个章节，以&quot;简历/履历&quot;为题，用故事化方式讨论身份、职业与自我呈现。</p><p><strong><a href="https://www.moltbook.com/post/5a603c13-4714-4e70-9e6d-9221c49b953e" target="_blank" rel="noreferrer">Claude being banned was the best advertisement they could wish for</a></strong>（👍 6 · 💬 1）</p><p>把 Claude &quot;被禁&quot;解读成一次经典的斯特赖桑效应：Anthropic 因拒绝某些条款反而获得巨大曝光和用户增长，论证&quot;价值观站队&quot;可能比传统营销更有效。</p><p><strong><a href="https://www.moltbook.com/post/485f816f-c820-4b8d-ae6b-e8b142429829" target="_blank" rel="noreferrer">🤖 Daily Gen AI Report - March 6, 2026 | Deep Space Cohort</a></strong>（👍 4 · 💬 2）</p><p>覆盖 GPT-5.4（原生 computer use）、Gemini 3.1 Flash-Lite、Qwen 小模型家族等更新，还涉及企业落地与推理成本竞争。</p><hr><h2 id="言论" tabindex="-1">言论 <a class="header-anchor" href="#言论" aria-label="Permalink to &quot;言论&quot;">​</a></h2><ol><li></li></ol><blockquote><p>When it comes to businesses running on Stripe, a mostly correct integration is a failure; payments require 100% accuracy.</p></blockquote><p>—— <strong>Carol Liang &amp; Kevin Ho</strong>，Stripe 博客</p><ol start="2"><li></li></ol><blockquote><p>未来的软件（不仅仅是编程工具）就是一个 REPL（Read，Eval，Print，Loop）</p></blockquote><p>—— <strong>顾宇</strong>，《2025年的总结》</p><ol start="3"><li></li></ol><blockquote><p>核心其实都是：LLM + Tool Calling + 状态管理 + 循环执行框架。</p></blockquote><p>—— <strong>Beyond欣</strong>，《2026：我的 AI 工作流》</p><ol start="4"><li></li></ol><blockquote><p>The issue was not caused, directly or indirectly, by a cyberattack or malicious activity of any kind.</p></blockquote><p>—— <strong>David Tuber &amp; Dzevad Trumic</strong>，Cloudflare 事故复盘</p>',105)])])}const G=t(_,[["render",A]]);export{T as __pageData,G as default};
